const staticData = $getWorkflowStaticData('global');
if (!staticData.queue) staticData.queue = [];
const pendingItems = staticData.queue.filter(i => i.status === 'pending' || i.status === 'retrying');
return [{ json: { queueLength: pendingItems.length, hasItems: pendingItems.length > 0, pendingItems, totalQueueSize: staticData.queue.length } }];

const items = $input.first().json.pendingItems || [];
if (items.length === 0) return [];
return items.map(item => ({ json: item }));

// Health check for the configured CRM — supports Activix and GHL
const provider = $env.CRM_PROVIDER || 'activix';

function getCrmConfig() {
  if (provider === 'ghl') {
    return {
      baseUrl: 'https://services.leadconnectorhq.com',
      headers: { 'Authorization': `Bearer ${$env.GHL_API_KEY}`, 'Version': '2021-07-28', 'Accept': 'application/json' },
    };
  }
  return {
    baseUrl: $env.ACTIVIX_API_URL || 'https://api.crm.activix.ca/v2',
    headers: { 'Authorization': `Bearer ${$env.ACTIVIX_API_TOKEN}`, 'Accept': 'application/json' },
  };
}

const config = getCrmConfig();
let healthy = false;
let responseData = {};

try {
  let url;
  if (provider === 'ghl') {
    const GHL_LOCATION_ID = $env.GHL_LOCATION_ID || '';
    url = `${config.baseUrl}/contacts/?locationId=${GHL_LOCATION_ID}&limit=1`;
  } else {
    url = `${config.baseUrl}/leads?per_page=1`;
  }

  const response = await fetch(url, {
    method: 'GET',
    headers: config.headers,
    signal: AbortSignal.timeout(10000),
  });

  if (response.ok) {
    responseData = await response.json();
    healthy = true;
  } else {
    responseData = { error: `HTTP ${response.status}`, status: response.status };
  }
} catch (err) {
  responseData = { error: err.message };
}

return [{ json: { ...responseData, _healthy: healthy, _provider: provider, data: healthy ? (responseData.data || responseData.contacts || []) : undefined } }];

// Execute queued CRM operation — supports Activix and GHL
const provider = $env.CRM_PROVIDER || 'activix';
const currentItem = $('Process Queue Items').item.json;
const leadData = currentItem.leadData || {};

function getCrmConfig() {
  if (provider === 'ghl') {
    return {
      baseUrl: 'https://services.leadconnectorhq.com',
      headers: { 'Authorization': `Bearer ${$env.GHL_API_KEY}`, 'Version': '2021-07-28', 'Content-Type': 'application/json', 'Accept': 'application/json' },
    };
  }
  return {
    baseUrl: $env.ACTIVIX_API_URL || 'https://api.crm.activix.ca/v2',
    headers: { 'Authorization': `Bearer ${$env.ACTIVIX_API_TOKEN}`, 'Content-Type': 'application/json', 'Accept': 'application/json' },
  };
}

const config = getCrmConfig();
const operation = currentItem.operation || 'create';
let result = { success: false, error: null, data: null };

try {
  if (provider === 'ghl') {
    const GHL_LOCATION_ID = $env.GHL_LOCATION_ID || '';
    let url, method, body;

    if (operation === 'update' && leadData.id) {
      url = `${config.baseUrl}/contacts/${leadData.id}`;
      method = 'PUT';
      // Map common fields to GHL format
      body = {
        firstName: leadData.first_name || leadData.firstName,
        lastName: leadData.last_name || leadData.lastName,
        email: leadData.email,
        phone: leadData.phone,
        tags: leadData.tags || [],
        customFields: leadData.customFields || [],
      };
    } else {
      url = `${config.baseUrl}/contacts/`;
      method = 'POST';
      body = {
        locationId: GHL_LOCATION_ID,
        firstName: leadData.first_name || leadData.firstName,
        lastName: leadData.last_name || leadData.lastName,
        email: leadData.email,
        phone: leadData.phone,
        tags: leadData.tags || ['nexus-queued'],
      };
    }

    // Remove undefined fields
    Object.keys(body).forEach(k => body[k] === undefined && delete body[k]);

    const response = await fetch(url, {
      method,
      headers: config.headers,
      body: JSON.stringify(body),
    });
    const data = await response.json();
    if (response.ok) result = { success: true, error: null, data };
    else throw new Error(data.message || `GHL error: ${response.status}`);
  } else {
    // Default: Activix
    let url = `${config.baseUrl}/leads`;
    let method = 'POST';
    if (operation === 'update' && leadData.id) {
      url = `${config.baseUrl}/leads/${leadData.id}`;
      method = 'PUT';
    }

    const response = await fetch(url, {
      method,
      headers: config.headers,
      body: JSON.stringify(leadData),
    });
    const data = await response.json();
    if (response.ok) result = { success: true, error: null, data };
    else throw new Error(`Activix error: ${response.status} ${JSON.stringify(data)}`);
  }
} catch (err) {
  result = { success: false, error: err.message, data: null };
}

return [{ json: { ...result, _provider: provider, _operation: operation } }];

const input = $input.first().json;
const currentItem = $('Process Queue Items').item.json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.queue) return [{ json: { status:'no_queue' } }];
const httpFailed = !input.success || input.error;
const idx = staticData.queue.findIndex(q => q.id === currentItem.id);
if (httpFailed) {
  if (idx >= 0) { staticData.queue[idx].attempts = (staticData.queue[idx].attempts||0)+1; staticData.queue[idx].lastError = input.error || 'HTTP error'; staticData.queue[idx].status = 'retrying'; }
  return [{ json: { status:'item_error', itemId:currentItem.id } }];
}
if (idx >= 0) { staticData.queue[idx].status = 'completed'; staticData.queue[idx].completedAt = new Date().toISOString(); }
return [{ json: { status:'completed', itemId:currentItem.id } }];

const provider = $env.CRM_PROVIDER || 'activix';
const providerLabel = provider === 'ghl' ? 'GHL' : 'Activix';
const currentItem = $('Process Queue Items').item.json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.queue) return [{ json: { status:'no_queue' } }];
const idx = staticData.queue.findIndex(q => q.id === currentItem.id);
if (idx >= 0) { staticData.queue[idx].attempts = (staticData.queue[idx].attempts||0)+1; staticData.queue[idx].lastError = `${providerLabel} API unhealthy`; staticData.queue[idx].status = 'retrying'; staticData.queue[idx].lastAttempt = new Date().toISOString(); }
const attempts = staticData.queue[idx]?.attempts || 0;
return [{ json: { itemId:currentItem.id, attempts, overLimit: attempts > 10, status:'retrying', provider: providerLabel } }];

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.queue) return [{ json: { status:'no_queue' } }];
const idx = staticData.queue.findIndex(q => q.id === input.itemId);
if (idx >= 0) { staticData.queue[idx].status = 'failed'; staticData.queue[idx].failedAt = new Date().toISOString(); staticData.queue[idx].lastError = `Exceeded max retries (10). ${input.provider || 'CRM'} API down 2.5+ hours.`; }
return [{ json: { status:'failed_permanently', itemId:input.itemId } }];
